CREATE VIEW `ads_trade_user_recharge_view` (`dt` COMMENT "统计日期", `product_id` COMMENT "产品id", `user_type` COMMENT "用户类型", `mt` COMMENT "终端", `core` COMMENT "core", `regcountry` COMMENT "注册国家", `appver` COMMENT "app版本", `pay_num` COMMENT "充值用户数", `pay_amount` COMMENT "充值总额") AS SELECT `dws`.`dws_trade_user_shopitem_charge_ed`.`dt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`Productid` AS `product_id`, if(`dws`.`dws_trade_user_shopitem_charge_ed`.`regdays` <= 7, 'n7', 'o7') AS `user_type`, `dws`.`dws_trade_user_shopitem_charge_ed`.`mt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`corever` AS `core`, `dws`.`dws_trade_user_shopitem_charge_ed`.`regcountry`, `dws`.`dws_trade_user_shopitem_charge_ed`.`appver`, count(DISTINCT `dws`.`dws_trade_user_shopitem_charge_ed`.`userid`) AS `pay_num`, sum(`dws`.`dws_trade_user_shopitem_charge_ed`.`chargemoney`) AS `pay_amount`
FROM `dws`.`dws_trade_user_shopitem_charge_ed`
GROUP BY 1, 2, 3, 4, 5, 6, 7 UNION ALL SELECT `dws`.`dws_trade_user_shopitem_charge_ed`.`dt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`Productid` AS `product_id`, if(`dws`.`dws_trade_user_shopitem_charge_ed`.`regdays` <= 30, 'n30', 'o30') AS `user_type`, `dws`.`dws_trade_user_shopitem_charge_ed`.`mt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`corever` AS `core`, `dws`.`dws_trade_user_shopitem_charge_ed`.`regcountry`, `dws`.`dws_trade_user_shopitem_charge_ed`.`appver`, count(DISTINCT `dws`.`dws_trade_user_shopitem_charge_ed`.`userid`) AS `pay_num`, sum(`dws`.`dws_trade_user_shopitem_charge_ed`.`chargemoney`) AS `pay_amount`
FROM `dws`.`dws_trade_user_shopitem_charge_ed`
GROUP BY 1, 2, 3, 4, 5, 6, 7 UNION ALL SELECT `dws`.`dws_trade_user_shopitem_charge_ed`.`dt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`Productid` AS `product_id`, if((`dws`.`dws_trade_user_shopitem_charge_ed`.`regdays` > 7) AND (`dws`.`dws_trade_user_shopitem_charge_ed`.`regdays` <= 30), 'n7_30', 'o7_30') AS `user_type`, `dws`.`dws_trade_user_shopitem_charge_ed`.`mt`, `dws`.`dws_trade_user_shopitem_charge_ed`.`corever` AS `core`, `dws`.`dws_trade_user_shopitem_charge_ed`.`regcountry`, `dws`.`dws_trade_user_shopitem_charge_ed`.`appver`, count(DISTINCT `dws`.`dws_trade_user_shopitem_charge_ed`.`userid`) AS `pay_num`, sum(`dws`.`dws_trade_user_shopitem_charge_ed`.`chargemoney`) AS `pay_amount`
FROM `dws`.`dws_trade_user_shopitem_charge_ed`
GROUP BY 1, 2, 3, 4, 5, 6, 7;